func ensureEstimatedUsageIfNeeded(ctx *gin.Context) {
    if ctx == nil {
        return
    }
    prompt := ctx.GetInt(meta.UpstreamPromptTokens)
    completion := ctx.GetInt(meta.UpstreamCompletionTokens)
    total := ctx.GetInt(meta.UpstreamTotalTokens)
    if prompt > 0 && completion > 0 {
        return
    }

    cfg := &onrusageestimate.Config{}
    onrusageestimate.ApplyDefaults(cfg)

    in := onrusageestimate.Input{
        Model: ctx.GetString(meta.RequestModel),
        PromptTokens: prompt,
        CompletionTokens: completion,
        TotalTokens: total,
        RequestBody: ctx.GetString(meta.RequestBody),
        StreamText: ctx.GetString(meta.StreamText),
        ResponseBody: ctx.GetString(meta.ResponseBody),
    }
    out := onrusageestimate.Estimate(cfg, in)
    if out.PromptTokens > 0 {
        ctx.Set(meta.UpstreamPromptTokens, out.PromptTokens)
    }
    if out.CompletionTokens > 0 {
        ctx.Set(meta.UpstreamCompletionTokens, out.CompletionTokens)
    }
    if out.TotalTokens > 0 {
        ctx.Set(meta.UpstreamTotalTokens, out.TotalTokens)
    }
}
